function obtenerValorPorDefecto(tipo) {
    switch(tipo) {
        case 'entero':
            return { tipo: 'literal', tipoDato: 'entero', valor: 0 };
        case 'decimal':
            return { tipo: 'literal', tipoDato: 'decimal', valor: 0.0 };
        case 'booleano':
            return { tipo: 'literal', tipoDato: 'booleano', valor: true };
        case 'caracter':
            return { tipo: 'literal', tipoDato: 'caracter', valor: '\u0000' };
        case 'cadena':
            return { tipo: 'literal', tipoDato: 'cadena', valor: '' };
        default:
            return null;
    }
}

function procesarCadena(cadena) {
    let valor = cadena.substring(1, cadena.length - 1);
    valor = valor.replace(/\\n/g, '\n');
    valor = valor.replace(/\\\\/g, '\\');
    valor = valor.replace(/\\"/g, '"');
    valor = valor.replace(/\\t/g, '\t');
    valor = valor.replace(/\\'/g, "'");
    return valor;
}
